lines = [line.strip() for line in raw_data.strip().split('\n') if line.strip()]
data = []

for line in lines:
    parts = line.split('\t')
    if len(parts) >= 14:
        roll_no = parts[1].strip()
        
        # Check condition: Starts with 7376222 or 7376221
        if roll_no.startswith('7376222') or roll_no.startswith('7376221'):
            name = parts[2].strip()
            gender = parts[3].strip()
            year = parts[4].strip()
            degree = parts[5].strip()
            dept = parts[6].strip()
            sem = parts[7].strip()
            quota = parts[8].strip()
            accomodation = parts[9].strip()
            fee = parts[13].replace(',', '').strip()
            
            data.append({
                'RollNo': roll_no,
                'Name': name,
                'Gender': gender,
                'Year': year,
                'Degree': degree,
                'Department': dept,
                'Semester': sem,
                'Quota': quota,
                'Accommodation': accomodation,
                'FeePending': float(fee) if fee.replace('.', '').isdigit() else fee
            })

df = pd.DataFrame(data)

# Let's also update the students_dataset.csv for the students present there
# We'll save the filtered list to a separate CSV and optionally update students_dataset.csv
df.to_csv('d:/AI Dropout Prediction System/fee_pending_list.csv', index=False)
print(f"Saved {len(df)} rows to fee_pending_list.csv")

# Now update students_dataset.csv with these new values if they exist
students_df = pd.read_csv('d:/AI Dropout Prediction System/students_dataset.csv')
updated_count = 0

for index, row in df.iterrows():
    roll_no = row['RollNo']
    fee = row['FeePending']
    
    # If student exists in our dataset, update feePending
    mask = students_df['studentId'] == roll_no
    if mask.any():
        students_df.loc[mask, 'feePending'] = fee
        updated_count += 1

students_df.to_csv('d:/AI Dropout Prediction System/students_dataset.csv', index=False)
